def solve(normal_glomeruli_pct, tubular_atrophy_fibrosis_pct, egfr_ml_per_min_per_1_73m2):
    # Step 1: assign_n_score - Assign score based on the percentage of normal glomeruli
    if normal_glomeruli_pct > 25:
        n_score = 0
    elif normal_glomeruli_pct >= 10:
        n_score = 4
    else:
        n_score = 6
    yield {
        "step_name": "assign_n_score",
        "step_description": "Assign score based on the percentage of normal glomeruli: >25% -> 0, 10-25% -> 4, <10% -> 6",
        "step_result": n_score,
        "unit": None
    }

    # Step 2: assign_t_score - Assign score based on the percentage of tubular atrophy and interstitial fibrosis
    if tubular_atrophy_fibrosis_pct <= 25:
        t_score = 0
    else:
        t_score = 2
    yield {
        "step_name": "assign_t_score",
        "step_description": "Assign score based on the percentage of tubular atrophy and interstitial fibrosis: <=25% -> 0, >25% -> 2",
        "step_result": t_score,
        "unit": None
    }

    # Step 3: assign_g_score - Assign score based on eGFR at diagnosis
    if egfr_ml_per_min_per_1_73m2 > 15:
        g_score = 0
    else:
        g_score = 3
    yield {
        "step_name": "assign_g_score",
        "step_description": "Assign score based on eGFR at diagnosis: >15 mL/min/1.73 m² -> 0, <=15 mL/min/1.73 m² -> 3",
        "step_result": g_score,
        "unit": None
    }

    # Step 4: calculate_total_risk_score - Sum N, T, and G scores to get the total ANCA Renal Risk Score
    total_score = n_score + t_score + g_score
    yield {
        "step_name": "calculate_total_risk_score",
        "step_description": "Sum N, T, and G scores to get the total ANCA Renal Risk Score",
        "step_result": total_score,
        "unit": None
    }

    return total_score
